1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Step = { op: string; items: Item[] };
3	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
4	type Scenario = { customer: Customer; steps: Step[] };
5	
6	const PROCESSING_FEE = 5;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const COMPONENT_TYPES = ["rune", "moonstone"];
18	const COMPONENT_BLOCK_SIZE = 3;
19	const COMPONENT_BLOCK_PRICE = 60;
20	
21	const CURSED_SURCHARGE_RATE = 0.5;
22	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	
25	const LOYALTY_DISCOUNT_RATE = 0.2;
26	const LOYALTY_MIN_YEARS = 2;
27	
28	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
29	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
30	
31	const baseForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;
32	
33	const isCursed = (item: Item): boolean => item.cursed === true;
34	
35	const isHighlyEnchanted = (item: Item): boolean =>
36	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
37	
38	const itemSurchargeRate = (item: Item): number =>
39	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
40	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
41	
42	const premiumForItem = (item: Item): number =>
43	  baseForType(item.type) * (1 + itemSurchargeRate(item));
44	
45	const countItemsOfType = (items: Item[], type: string): number =>
46	  items.filter((item) => item.type === type).length;
47	
48	const premiumForComponentType = (items: Item[], type: string): number => {
49	  const count = countItemsOfType(items, type);
50	  return count === COMPONENT_BLOCK_SIZE
51	    ? COMPONENT_BLOCK_PRICE
52	    : count * baseForType(type);
53	};
54	
55	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
56	
57	const basePremiumFor = (items: Item[]): number => {
58	  const componentsTotal = COMPONENT_TYPES.reduce(
59	    (sum, type) => sum + premiumForComponentType(items, type),
60	    0,
61	  );
62	  const nonComponentsTotal = items
63	    .filter((item) => !isComponent(item))
64	    .reduce((sum, item) => sum + premiumForItem(item), 0);
65	  return componentsTotal + nonComponentsTotal;
66	};
67	
68	const loyaltyRate = (customer: Customer): number =>
69	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS ? -LOYALTY_DISCOUNT_RATE : 0;
70	
71	const firstInsuranceRate = (customer: Customer): number =>
72	  customer.previousContracts !== undefined ? FIRST_INSURANCE_SURCHARGE_RATE : 0;
73	
74	const followUpRate = (customer: Customer): number =>
75	  (customer.previousContracts ?? 0) >= 1 ? -FOLLOW_UP_DISCOUNT_RATE : 0;
76	
77	const policyAdjustmentRate = (customer: Customer): number =>
78	  loyaltyRate(customer) + firstInsuranceRate(customer) + followUpRate(customer);
79	
80	const roundToCents = (value: number): number => Math.round(value * 100) / 100;
81	
82	const quotePremium = (items: Item[], customer: Customer): number => {
83	  const policyBase = basePremiumFor(items);
84	  const policyAdjustment = policyBase * policyAdjustmentRate(customer);
85	  return roundToCents(policyBase + policyAdjustment + PROCESSING_FEE);
86	};
87	
88	export const runScenario = (input: unknown): { results: Array<{ premium: number }> } => {
89	  const { customer, steps } = input as Scenario;
90	  return { results: [{ premium: quotePremium(steps[0].items, customer) }] };
91	};
